                            onBackToSetup: () => { setIsWordSoundsMode(false); setCurrentWordSoundsWord(null); setWordSoundsPhonemes(null); setWordSoundsFeedback(null); setWordSoundsActivity(null); setWordSoundsAutoReview(false); setActiveView('word-sounds-generator'); },
